import{_ as d,C as i,o as n,c as l,j as t,a,E as o,ag as r}from"./chunks/framework.DLWhSH9p.js";const y=JSON.parse('{"title":"Episodes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/episodes.md","filePath":"guide/episodes.md"}'),p={name:"guide/episodes.md"};function c(h,e,u,g,m,b){const s=i("SchemeImage");return n(),l("div",null,[e[0]||(e[0]=t("h1",{id:"episodes",tabindex:"-1"},[a("Episodes "),t("a",{class:"header-anchor",href:"#episodes","aria-label":'Permalink to "Episodes"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("Episodes represent complete video productions that move through an 8-stage pipeline orchestrated by AI agents with automated quality gates. Reach Episodes from the top-chrome stage rail — "),t("strong",null,"Episodes"),a(" is the rightmost stage.")],-1)),o(s,{name:"episodes-panel",alt:"Episodes panel"}),e[2]||(e[2]=r('<h2 id="episode-detail-layout" tabindex="-1">Episode detail layout <a class="header-anchor" href="#episode-detail-layout" aria-label="Permalink to &quot;Episode detail layout&quot;">​</a></h2><p>Click any episode card to open the detail view. It has three stacked sections:</p><ul><li><strong>Header</strong> — episode title, slug, target duration, action buttons (Delete · Composition · Run Pipeline).</li><li><strong>Preview</strong> — <strong>collapsed by default</strong>. The header row shows a live status chip (<code>video ready</code> / <code>composition ready</code> / <code>not available</code>). Expand it only when you want to watch — that keeps the pipeline in view while you work.</li><li><strong>Pipeline Stages</strong> — one row per stage with status dot, name, status chip, and contextual actions.</li></ul>',3)),o(s,{name:"episode-detail",alt:"Episode detail — collapsed preview + pipeline stages"}),e[3]||(e[3]=r(`<h2 id="pipeline-stages" tabindex="-1">Pipeline stages <a class="header-anchor" href="#pipeline-stages" aria-label="Permalink to &quot;Pipeline stages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>Agent</th><th>Reviewer</th><th>Max iterations</th><th>Description</th></tr></thead><tbody><tr><td><strong>Research</strong></td><td>Researcher</td><td>Producer</td><td>2</td><td>Gather facts, sources, competitive analysis, define unique angle</td></tr><tr><td><strong>Script</strong></td><td>Writer</td><td>Producer</td><td>3</td><td>Write screenplay in channel character voice</td></tr><tr><td><strong>Storyboard</strong></td><td>Storyboarder</td><td>Producer</td><td>2</td><td>Plan visual sequences and scene layouts</td></tr><tr><td><strong>Assets</strong></td><td>Asset Finder</td><td>—</td><td>1</td><td>Find and download media resources</td></tr><tr><td><strong>Compositing</strong></td><td>Compositor</td><td>Producer</td><td>3</td><td>Assemble Remotion video from 65+ components</td></tr><tr><td><strong>Export</strong></td><td>Render Worker</td><td>—</td><td>1</td><td>Render final MP4 via Chromium (dispatched to <code>worker-render</code>)</td></tr><tr><td><strong>Review</strong></td><td>Producer</td><td>—</td><td>1</td><td>Holistic quality gate across all artifacts — always requires human approval</td></tr><tr><td><strong>Publish</strong></td><td>—</td><td>—</td><td>1</td><td>Guard on review approval, mark episode complete</td></tr></tbody></table><h2 id="storyboard-stage-—-open-editor" tabindex="-1">Storyboard stage — Open editor <a class="header-anchor" href="#storyboard-stage-—-open-editor" aria-label="Permalink to &quot;Storyboard stage — Open editor&quot;">​</a></h2><p>The storyboard stage row has a special <strong>Open editor</strong> button. It jumps to the <a href="/guide/storyboard.html">Storyboard editor</a> for this episode — a dedicated UI for planning per-scene visuals, shot types, and attached image/clip resources. That&#39;s normally where you&#39;d land rather than running the AI storyboarder directly. If the episode has a linked script, the editor auto-populates; otherwise there&#39;s a script dropdown to pick one.</p><h2 id="execution-modes" tabindex="-1">Execution modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution modes&quot;">​</a></h2><ul><li><strong>Full Pipeline</strong> — click <strong>Run Pipeline</strong> in the header to execute from the next pending stage through to completion (or until a stage requires human intervention).</li><li><strong>Single Stage</strong> — click <strong>Run</strong> on any individual stage row to execute just that stage.</li></ul><h2 id="quality-gates" tabindex="-1">Quality gates <a class="header-anchor" href="#quality-gates" aria-label="Permalink to &quot;Quality gates&quot;">​</a></h2><p>The producer agent scores each stage output 1–10. Stages scoring 7+ pass automatically. Failed stages trigger a feedback loop:</p><ol><li>Producer writes structured revision notes.</li><li>Notes are saved as stage feedback.</li><li>The responsible agent re-runs with the feedback context.</li><li>Repeat up to the stage&#39;s max iterations.</li></ol><p>If iterations exhaust without passing, the stage is marked <code>needs_human</code> and the pipeline pauses for manual intervention.</p><h3 id="upstream-issues" tabindex="-1">Upstream issues <a class="header-anchor" href="#upstream-issues" aria-label="Permalink to &quot;Upstream issues&quot;">​</a></h3><p>If the producer identifies a problem originating from an earlier stage (e.g., a weak script caused by thin research), both the current stage and the upstream stage are marked <code>changes_requested</code>. The pipeline halts so a human can decide whether to re-run the upstream stage.</p><h3 id="soft-recovery" tabindex="-1">Soft recovery <a class="header-anchor" href="#soft-recovery" aria-label="Permalink to &quot;Soft recovery&quot;">​</a></h3><p>If an agent hits its turn limit but still produced the expected artifact (e.g., <code>research.md</code> exists), the orchestrator proceeds to review rather than hard-failing — the artifact may be good enough to pass.</p><h2 id="stage-statuses" tabindex="-1">Stage statuses <a class="header-anchor" href="#stage-statuses" aria-label="Permalink to &quot;Stage statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Colour</th></tr></thead><tbody><tr><td><code>not_started</code></td><td>Stage hasn&#39;t been run</td><td>Gray</td></tr><tr><td><code>in_progress</code></td><td>Agent or render currently executing</td><td>Blue (pulsing)</td></tr><tr><td><code>review</code></td><td>Producer is evaluating the output</td><td>Yellow</td></tr><tr><td><code>complete</code></td><td>Stage passed quality gate</td><td>Green</td></tr><tr><td><code>approved</code></td><td>Human explicitly approved (review stage)</td><td>Green</td></tr><tr><td><code>changes_requested</code></td><td>Feedback provided, needs re-run</td><td>Gray</td></tr><tr><td><code>needs_human</code></td><td>Max iterations exhausted or human gate</td><td>Pink</td></tr><tr><td><code>error</code></td><td>Agent or render failed</td><td>Red</td></tr></tbody></table><h2 id="artifact-viewers" tabindex="-1">Artifact viewers <a class="header-anchor" href="#artifact-viewers" aria-label="Permalink to &quot;Artifact viewers&quot;">​</a></h2><p>Research, script, and storyboard rows have a chevron for viewing the produced artifact inline. The artifact is a text blob fetched from <code>/channels/:channelId/episodes/:episodeId/artifacts/:stage</code>. For <strong>storyboard</strong>, the artifact is a summary — the full interactive editor is behind <strong>Open editor</strong>.</p><h2 id="composition" tabindex="-1">Composition <a class="header-anchor" href="#composition" aria-label="Permalink to &quot;Composition&quot;">​</a></h2><p>The header&#39;s <strong>Composition</strong> button opens the timeline editor for direct composition editing (Remotion composition format). Useful for fine-tuning once the AI has produced a first pass.</p><h2 id="episode-files" tabindex="-1">Episode files <a class="header-anchor" href="#episode-files" aria-label="Permalink to &quot;Episode files&quot;">​</a></h2><p>Each episode lives in <code>channels/{channel}/episodes/{slug}/</code> with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>manifest.yml          # Pipeline state (stage statuses + scriptId + audioProjectId)</span></span>
<span class="line"><span>research.md           # Research output</span></span>
<span class="line"><span>script.md             # Written screenplay</span></span>
<span class="line"><span>storyboard.md         # Visual plan (or JSON if generated)</span></span>
<span class="line"><span>Episode.tsx           # Remotion composition</span></span>
<span class="line"><span>feedback/             # Producer review notes per stage</span></span>
<span class="line"><span>  research.md</span></span>
<span class="line"><span>  script.md</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>output/               # Rendered video</span></span>
<span class="line"><span>  {slug}.mp4</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Episodes require NATS workers. Workers are deployed as Kubernetes Deployments in Helm (see the <code>workers</code> values section). For local dev: <code>docker compose -f docker-compose.dev.yml up -d</code>.</p></div>`,24))])}const v=d(p,[["render",c]]);export{y as __pageData,v as default};
